// Pull fields out of the Notion page and choose a style preset.
const input = $('Sub-workflow Trigger').first().json;
const page  = $json;
const props = page.properties || {};
function txt(name) { return props[name]?.rich_text?.[0]?.plain_text || ''; }
function title(name) { return props[name]?.title?.[0]?.plain_text || ''; }
function num(name) { return props[name]?.number ?? null; }
function sel(name) { return props[name]?.select?.name || ''; }
function chk(name) { return Boolean(props[name]?.checkbox); }

const data = {
  案名: title('案名'),
  社區名稱: txt('社區名稱'),
  地址: txt('地址'),
  總價: txt('總價'),
  單價: txt('單價'),
  格局: txt('格局'),
  樓層: txt('樓層'),
  屋齡: num('屋齡'),
  主建物坪數: num('主建物坪數'),
  公設坪數: num('公設坪數'),
  建物坪數: num('建物坪數'),
  土地坪數: num('土地坪數'),
  附屬建物: txt('附屬建物'),
  特色說明: txt('特色說明'),
  建物類型: sel('建物類型'),
  車位類型: sel('車位類型'),
  有無車位: chk('有無車位')
};

let style = input.style || sel('文案風格') || 'AI判斷';
if (!['首購溫馨', '投資自用', '急售吸睛', 'AI判斷'].includes(style)) style = 'AI判斷';

const styleHint = {
  '首購溫馨': '溫馨、生活感、適合首購族；強調採光、生活機能、家的感覺。',
  '投資自用': '理性、聚焦投報率與保值；強調地段、學區、租金行情。',
  '急售吸睛': '節奏明快、重點直球；用「降價」「屋主急售」「市場稀缺」之類強鉤子。',
  'AI判斷': '依物件特性自動挑選最合適的調性。'
}[style];

const current文案版本 = num('文案版本') ?? 0;

const userPrompt = [
  '你是台灣不動產廣告文案高手，幫永慶博愛凱璿加盟店寫一則臉書社團貼文文案。',
  '',
  `風格：${style}（${styleHint}）`,
  '',
  '物件資料：',
  ...Object.entries(data)
    .filter(([, v]) => v !== '' && v !== null && v !== undefined && v !== false)
    .map(([k, v]) => `- ${k}：${v}`),
  '',
  '輸出要求：',
  '1) 200~280 字，含 emoji，分行清楚。',
  '2) 開頭一句鉤子，結尾留聯絡引導（不要寫電話／姓名，由人工補）。',
  '3) 不要編造資料；資料缺的欄位略過即可。',
  '4) 直接輸出文案本體，不要前後加說明或標題。'
].join('\n');

return [{
  json: {
    pageId: page.id,
    style,
    nextVersion: current文案版本 + 1,
    userPrompt
  }
}];

// Extract text from Anthropic response and pass version forward.
const meta = $('Build Prompt').first().json;
const resp = $json;
const text = (resp?.content || [])
  .filter(c => c.type === 'text')
  .map(c => c.text)
  .join('\n')
  .trim();
if (!text) throw new Error('Claude 回傳為空：' + JSON.stringify(resp).slice(0, 400));
return [{
  json: {
    pageId: meta.pageId,
    style: meta.style,
    nextVersion: meta.nextVersion,
    copy: text
  }
}];

const meta = $('Extract Copy').first().json;
const page = $json;
return [{
  json: {
    pageId: meta.pageId,
    notionPageUrl: page?.url || page?.public_url || '',
    style: meta.style,
    version: meta.nextVersion,
    copy: meta.copy
  }
}];
